const alert = $input.item.json.alert;
const runDate = $input.item.json.body?.run_date || '';

const directionEmoji = {
  up: '🟢',
  down: '🔴',
  neutral: '🟡'
}[alert.direction] || '⚪';

const directionLabel = {
  up: '↑ UP',
  down: '↓ DOWN',
  neutral: '→ NEUTRAL'
}[alert.direction] || alert.direction;

const signalLabel = {
  quality: 'Quality',
  momentum: 'Momentum',
  news_catalyst: 'News Catalyst',
  risk_flag: '⚠️ Data Risk'
}[alert.signal_type] || alert.signal_type;

const scoreStr = alert.score != null ? `Score: ${alert.score.toFixed(1)}` : '';
const narrativeStr = alert.narrative ? `\n\n${alert.narrative}` : '';

const tag = `#${alert.ticker} #${alert.signal_type.replace('_', '')} #alert`;

const message = [
  `${directionEmoji} *${alert.ticker}* — ${signalLabel} Signal`,
  `📊 ${scoreStr} | Severity: ${alert.severity.toUpperCase()} | Direction: ${directionLabel}`,
  `📅 ${runDate}`,
  narrativeStr,
  '',
  tag
].filter(l => l !== undefined).join('\n');

return [{ json: { message } }];
